# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

import os
from functools import lru_cache

from flask import Flask, jsonify, request
from elasticsearch import Elasticsearch
from elasticsearch.exceptions import ElasticsearchException

app = Flask(__name__)

ELASTICSEARCH_URL = os.getenv("ELASTICSEARCH_URL", "http://localhost:9200")
ELASTICSEARCH_INDEX = os.getenv("ELASTICSEARCH_INDEX", "products")
SEARCH_TIMEOUT = os.getenv("SEARCH_TIMEOUT", "200ms")
MAX_QUERY_LENGTH = int(os.getenv("MAX_QUERY_LENGTH", "100"))
DEFAULT_PAGE_SIZE = int(os.getenv("DEFAULT_PAGE_SIZE", "20"))
MAX_PAGE_SIZE = int(os.getenv("MAX_PAGE_SIZE", "100"))


@lru_cache(maxsize=1)
def get_es_client():
    return Elasticsearch(
        ELASTICSEARCH_URL,
        request_timeout=2,
        retry_on_timeout=True,
        max_retries=3,
    )


def clamp(value, minimum, maximum):
    return max(minimum, min(value, maximum))


@app.get("/api/search")
def search_products():
    q = request.args.get("q", "", type=str).strip()
    if not q:
        return jsonify({"error": "Missing required query parameter: q"}), 400

    if len(q) > MAX_QUERY_LENGTH:
        return jsonify({"error": f"Query too long. Max length is {MAX_QUERY_LENGTH}"}), 400

    page = request.args.get("page", default=1, type=int)
    size = request.args.get("size", default=DEFAULT_PAGE_SIZE, type=int)
    page = max(1, page)
    size = clamp(size, 1, MAX_PAGE_SIZE)
    from_ = (page - 1) * size

    es_query = {
        "from": from_,
        "size": size,
        "track_total_hits": False,
        "timeout": SEARCH_TIMEOUT,
        "_source": ["id", "name", "description", "price", "currency", "image_url", "category", "brand"],
        "query": {
            "bool": {
                "should": [
                    {
                        "multi_match": {
                            "query": q,
                            "type": "best_fields",
                            "fields": [
                                "name^5",
                                "brand^3",
                                "category^2",
                                "description"
                            ],
                            "operator": "and",
                            "fuzziness": "AUTO"
                        }
                    },
                    {
                        "multi_match": {
                            "query": q,
                            "type": "phrase_prefix",
                            "fields": [
                                "name^6",
                                "brand^3"
                            ]
                        }
                    }
                ],
                "minimum_should_match": 1
            }
        },
        "sort": [
            "_score",
            {"_id": "asc"}
        ]
    }

    try:
        es = get_es_client()
        response = es.search(index=ELASTICSEARCH_INDEX, body=es_query)

        hits = response.get("hits", {}).get("hits", [])
        products = []
        for hit in hits:
            source = hit.get("_source", {})
            source["score"] = hit.get("_score")
            products.append(source)

        return jsonify({
            "query": q,
            "page": page,
            "size": size,
            "count": len(products),
            "products": products
        }), 200

    except ElasticsearchException:
        return jsonify({"error": "Search service unavailable"}), 503


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "5000")))